import{_ as e,o as n,c as t,aq as i}from"./chunks/framework.DH0nG2Fl.js";const g=JSON.parse('{"title":"Your First Extension","description":"","frontmatter":{"prev":{"text":"Extension Development","link":"/development/extensions/"},"next":{"text":"First Edits","link":"/development/extensions/first-edits"}},"headers":[],"relativePath":"development/extensions/start.md","filePath":"development/extensions/start.md","lastUpdated":1782516350000}'),a={name:"development/extensions/start.md"};function o(r,s,l,p,d,h){return n(),t("div",null,[...s[0]||(s[0]=[i(`<h1 id="your-first-extension" tabindex="-1">Your First Extension <a class="header-anchor" href="#your-first-extension" aria-label="Permalink to “Your First Extension”">​</a></h1><p>This guide assumes you have <strong>git</strong> and <strong>npm</strong> installed. If not, you can get them here: <a href="https://git-scm.com/install/" target="_blank" rel="noreferrer">git</a> · <a href="https://docs.npmjs.com/downloading-and-installing-node-js-and-npm" target="_blank" rel="noreferrer">npm / Node.js</a></p><p>Start by cloning the template repository and installing its dependencies:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/inkdex/template-extensions</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> template-extensions</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><p>This repository is the standard template for an Inkdex extension. It comes pre-configured with all the tooling used across Inkdex&#39;s own extension repos.</p><h2 id="repository-structure" tabindex="-1">Repository structure <a class="header-anchor" href="#repository-structure" aria-label="Permalink to “Repository structure”">​</a></h2><p>Here is a quick overview of what is inside:</p><ul><li><strong><code>package.json</code></strong> : declares all dependencies and the scripts used to build, run, and debug the extension.</li><li><strong><code>tsconfig.json</code></strong> : TypeScript compiler settings shared across all Inkdex extensions.</li><li><strong><code>.oxfmtrc.json</code> / <code>.oxlintrc.json</code></strong> : formatting and linting rules to keep code style consistent.</li><li><strong><code>README.md</code>, <code>LICENSE</code>, <code>.gitignore</code>, <code>.github/</code>, <code>.husky/</code></strong> : standard project files; nothing to worry about for now.</li></ul><p>All the code that matters lives in <code>src/</code>, which contains two directories:</p><ul><li><strong><code>src/test/</code></strong> : test harness to verify that your extension runs correctly and has no major issues.</li><li><strong><code>src/ContentTemplate/</code></strong> : the extension itself. This is where you will spend most of your time. We will rename this directory in the next step to match your extension.</li></ul><h2 id="installing-on-your-phone" tabindex="-1">Installing on your phone <a class="header-anchor" href="#installing-on-your-phone" aria-label="Permalink to “Installing on your phone”">​</a></h2><p>Make sure your phone and computer are on the <strong>same local network</strong>, then run:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><p>This command builds your extension and starts a local server, allowing you to load and hot-reload the extension directly on your device. You should see output similar to:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Building Sources</span></span>
<span class="line"><span>Working directory: /home/user/template-extensions</span></span>
<span class="line"><span>✔ Bundle Sources [17ms]</span></span>
<span class="line"><span>  ✔ Transpiling Project [13ms]</span></span>
<span class="line"><span>  ✔ Generate SourceInfo [0ms]</span></span>
<span class="line"><span>    ✔ ContentTemplate [0ms]</span></span>
<span class="line"><span>✔ Generate Versioning File [3ms]</span></span>
<span class="line"><span>✔ Generate Homepage [2ms]</span></span>
<span class="line"><span>Server running at http://127.0.0.1:8080/</span></span>
<span class="line"><span>Server running at http://192.168.1.xx:8080/</span></span>
<span class="line"><span>For a list of commands do h or help</span></span>
<span class="line"><span>[23:24:33:0115]</span></span></code></pre></div><p>The exact output may differ slightly, but the important line is the local network address (<code>192.168.1.xx:8080</code>).</p><p>On your phone, add an extension repository using that address, for example <code>http://192.168.1.105:8080/</code>. You should see <strong>ContentTemplate</strong> available to download. That is your first extension, congratulations!</p><hr><p>In the next guide, we will open up that extension and start editing it to make it our own.</p>`,19)])])}const u=e(a,[["render",o]]);export{g as __pageData,u as default};
